// frontend/src/components/jobs/JobDetail.jsx
import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import api from '../../services/api'; // Pastikan path ke api service benar

const JobDetail = () => {
    const { id } = useParams();
    const navigate = useNavigate();
    const [job, setJob] = useState(null);

    useEffect(() => {
        // Ambil detail lowongan berdasarkan ID dari API
        api.get(`/jobs/${id}`) 
            .then(res => setJob(res.data))
            .catch(err => console.error("Gagal memuat detail:", err));
    }, [id]);

    if (!job) return <div>Memuat...</div>;

    return (
        <div style={{ maxWidth: '800px', margin: '40px auto', padding: '20px', color: '#fef3c7' }}>
            <h2>{job.title}</h2>
            <p>Gaji: {job.gaji}</p>
            <p>{job.desc}</p>
            {/* ... render detail lainnya ... */}
        </div>
    );
};
